-- Add HeaderTemplate and FooterTemplate columns
IF NOT EXISTS (SELECT * FROM sys.columns WHERE object_id = OBJECT_ID('dbo.EmailTemplate') AND name = 'HeaderTemplate')
BEGIN
    ALTER TABLE dbo.EmailTemplate ADD HeaderTemplate ntext NULL;
END
GO

IF NOT EXISTS (SELECT * FROM sys.columns WHERE object_id = OBJECT_ID('dbo.EmailTemplate') AND name = 'FooterTemplate')
BEGIN
    ALTER TABLE dbo.EmailTemplate ADD FooterTemplate ntext NULL;
END
GO

-- Seed _HEADER template (system, not deletable)
-- Single rawhtml component containing the logo section
IF NOT EXISTS (SELECT 1 FROM dbo.EmailTemplate WHERE TemplateName = '_HEADER')
BEGIN
    INSERT INTO dbo.EmailTemplate (TemplateName, TemplateType, Template, EmailSubject, IsActive, IsDeleted, AddedOn, AddedBy, DeletedBy, HeaderTemplate, FooterTemplate)
    VALUES (
        '_HEADER',
        'sys',
        N'<div data-yo-c="true" data-yo-id="comp_header" data-yo-type="rawhtml" data-yo-name="Raw HTML" data-yo-config="{&quot;content&quot;:&quot;<table width=\&quot;100%\&quot; border=\&quot;0\&quot; cellspacing=\&quot;0\&quot; cellpadding=\&quot;0\&quot;><tr><td align=\&quot;center\&quot; style=\&quot;padding:30px 15px;\&quot;><a href=\&quot;{{app_url}}\&quot; target=\&quot;_blank\&quot;><img src=\&quot;{{logo_url}}\&quot; width=\&quot;180\&quot; border=\&quot;0\&quot; alt=\&quot;{{app_name}}\&quot; style=\&quot;display:block; margin:0 auto; height:auto;\&quot; /></a></td></tr></table>&quot;}"><table width="100%" border="0" cellspacing="0" cellpadding="0"><tr><td align="center" style="padding:30px 15px;"><a href="{{app_url}}" target="_blank"><img src="{{logo_url}}" width="180" border="0" alt="{{app_name}}" style="display:block; margin:0 auto; height:auto;" /></a></td></tr></table></div>',
        '',
        1, 0, GETUTCDATE(), 1, 0, '', '');
END
GO

-- Seed _FOOTER template (system, not deletable)
-- Single rawhtml component containing dark footer + social icons + company info + legal links
