BEGIN
    INSERT INTO dbo.EmailTemplate (TemplateName, TemplateType, Template, EmailSubject, IsActive, IsDeleted, AddedOn, AddedBy, DeletedBy, HeaderTemplate, FooterTemplate)
    VALUES (
        '_FOOTER',
        'sys',
        N'<div data-yo-c="true" data-yo-id="comp_footer" data-yo-type="rawhtml" data-yo-name="Raw HTML" data-yo-config="{&quot;content&quot;:&quot;<table width=\&quot;100%\&quot; border=\&quot;0\&quot; cellspacing=\&quot;0\&quot; cellpadding=\&quot;0\&quot;><tr><td bgcolor=\&quot;#203244\&quot; style=\&quot;border-radius:0 0 10px 10px; padding:50px;\&quot;><table width=\&quot;100%\&quot; border=\&quot;0\&quot; cellspacing=\&quot;0\&quot; cellpadding=\&quot;0\&quot;><tr><td align=\&quot;center\&quot; style=\&quot;padding-bottom:25px;\&quot;><a href=\&quot;{{app_url}}\&quot; target=\&quot;_blank\&quot;><img src=\&quot;{{logo_url}}\&quot; width=\&quot;180\&quot; border=\&quot;0\&quot; alt=\&quot;{{app_name}}\&quot; style=\&quot;height:auto; display:block; margin:0 auto;\&quot; /></a></td></tr><tr><td align=\&quot;center\&quot; style=\&quot;padding-bottom:20px;\&quot;><table border=\&quot;0\&quot; cellspacing=\&quot;0\&quot; cellpadding=\&quot;0\&quot;><tr><td width=\&quot;34\&quot;><a href=\&quot;{FacebookUrl}\&quot; target=\&quot;_blank\&quot;><img src=\&quot;https://www.psd2newsletters.com/templates/purple/images/ico_facebook.png\&quot; width=\&quot;34\&quot; height=\&quot;34\&quot; border=\&quot;0\&quot; alt=\&quot;Facebook\&quot; /></a></td><td width=\&quot;15\&quot;></td><td width=\&quot;34\&quot;><a href=\&quot;{InstagramUrl}\&quot; target=\&quot;_blank\&quot;><img src=\&quot;https://www.psd2newsletters.com/templates/purple/images/ico_instagram.png\&quot; width=\&quot;34\&quot; height=\&quot;34\&quot; border=\&quot;0\&quot; alt=\&quot;Instagram\&quot; /></a></td><td width=\&quot;15\&quot;></td><td width=\&quot;34\&quot;><a href=\&quot;{TwitterUrl}\&quot; target=\&quot;_blank\&quot;><img src=\&quot;https://www.psd2newsletters.com/templates/purple/images/ico_twitter.png\&quot; width=\&quot;34\&quot; height=\&quot;34\&quot; border=\&quot;0\&quot; alt=\&quot;Twitter\&quot; /></a></td><td width=\&quot;15\&quot;></td><td width=\&quot;34\&quot;><a href=\&quot;{PinterestUrl}\&quot; target=\&quot;_blank\&quot;><img src=\&quot;https://www.psd2newsletters.com/templates/purple/images/ico_pinterest.png\&quot; width=\&quot;34\&quot; height=\&quot;34\&quot; border=\&quot;0\&quot; alt=\&quot;Pinterest\&quot; /></a></td></tr></table></td></tr><tr><td style=\&quot;font-size:14px; line-height:24px; text-align:center; color:#ffffff; padding-bottom:20px; font-family:Arial, Helvetica, sans-serif;\&quot;>{{company_name}}<br />{{company_address}}<br /><a href=\&quot;mailto:{{company_email}}\&quot; target=\&quot;_blank\&quot; style=\&quot;text-decoration:none; color:#ffffff;\&quot;>{{company_email}}</a> - <a href=\&quot;{{app_url}}\&quot; target=\&quot;_blank\&quot; style=\&quot;text-decoration:none; color:#ffffff;\&quot;>{{app_url}}</a></td></tr></table></td></tr></table><table width=\&quot;100%\&quot; border=\&quot;0\&quot; cellspacing=\&quot;0\&quot; cellpadding=\&quot;0\&quot;><tr><td style=\&quot;font-size:12px; color:#6f7b8a; line-height:22px; text-align:center; padding-top:20px; padding-bottom:20px; font-family:Arial, Helvetica, sans-serif;\&quot;><a href=\&quot;{UnsubscribeUrl}\&quot; target=\&quot;_blank\&quot; style=\&quot;text-decoration:none; color:#6f7b8a;\&quot;>UNSUBSCRIBE</a> | <a href=\&quot;{WebVersionUrl}\&quot; target=\&quot;_blank\&quot; style=\&quot;text-decoration:none; color:#6f7b8a;\&quot;>WEB VERSION</a> | <a href=\&quot;{ShareUrl}\&quot; target=\&quot;_blank\&quot; style=\&quot;text-decoration:none; color:#6f7b8a;\&quot;>SEND TO A FRIEND</a></td></tr></table>&quot;}"><table width="100%" border="0" cellspacing="0" cellpadding="0"><tr><td bgcolor="#203244" style="border-radius:0 0 10px 10px; padding:50px;"><table width="100%" border="0" cellspacing="0" cellpadding="0"><tr><td align="center" style="padding-bottom:25px;"><a href="{{app_url}}" target="_blank"><img src="{{logo_url}}" width="180" border="0" alt="{{app_name}}" style="height:auto; display:block; margin:0 auto;" /></a></td></tr><tr><td align="center" style="padding-bottom:20px;"><table border="0" cellspacing="0" cellpadding="0"><tr><td width="34"><a href="{FacebookUrl}" target="_blank"><img src="https://www.psd2newsletters.com/templates/purple/images/ico_facebook.png" width="34" height="34" border="0" alt="Facebook" /></a></td><td width="15"></td><td width="34"><a href="{InstagramUrl}" target="_blank"><img src="https://www.psd2newsletters.com/templates/purple/images/ico_instagram.png" width="34" height="34" border="0" alt="Instagram" /></a></td><td width="15"></td><td width="34"><a href="{TwitterUrl}" target="_blank"><img src="https://www.psd2newsletters.com/templates/purple/images/ico_twitter.png" width="34" height="34" border="0" alt="Twitter" /></a></td><td width="15"></td><td width="34"><a href="{PinterestUrl}" target="_blank"><img src="https://www.psd2newsletters.com/templates/purple/images/ico_pinterest.png" width="34" height="34" border="0" alt="Pinterest" /></a></td></tr></table></td></tr><tr><td style="font-size:14px; line-height:24px; text-align:center; color:#ffffff; padding-bottom:20px; font-family:Arial, Helvetica, sans-serif;">{{company_name}}<br />{{company_address}}<br /><a href="mailto:{{company_email}}" target="_blank" style="text-decoration:none; color:#ffffff;">{{company_email}}</a> - <a href="{{app_url}}" target="_blank" style="text-decoration:none; color:#ffffff;">{{app_url}}</a></td></tr></table></td></tr></table><table width="100%" border="0" cellspacing="0" cellpadding="0"><tr><td style="font-size:12px; color:#6f7b8a; line-height:22px; text-align:center; padding-top:20px; padding-bottom:20px; font-family:Arial, Helvetica, sans-serif;"><a href="{UnsubscribeUrl}" target="_blank" style="text-decoration:none; color:#6f7b8a;">UNSUBSCRIBE</a> | <a href="{WebVersionUrl}" target="_blank" style="text-decoration:none; color:#6f7b8a;">WEB VERSION</a> | <a href="{ShareUrl}" target="_blank" style="text-decoration:none; color:#6f7b8a;">SEND TO A FRIEND</a></td></tr></table></div>',
        '',
        1, 0, GETUTCDATE(), 1, 0, '', '');
END
GO

-- Update existing templates to use header/footer if they have none
UPDATE dbo.EmailTemplate
SET HeaderTemplate = (SELECT Template FROM dbo.EmailTemplate WHERE TemplateName = '_HEADER'),
    FooterTemplate = (SELECT Template FROM dbo.EmailTemplate WHERE TemplateName = '_FOOTER')
WHERE HeaderTemplate IS NULL AND FooterTemplate IS NULL AND TemplateName NOT IN ('_HEADER', '_FOOTER');
GO

-- Seed OTP Login template with rawhtml component
IF NOT EXISTS (SELECT 1 FROM dbo.EmailTemplate WHERE TemplateName = 'otp_login')
BEGIN
    INSERT INTO dbo.EmailTemplate (TemplateName, TemplateType, Template, EmailSubject, IsActive, IsDeleted, AddedOn, AddedBy, DeletedBy, HeaderTemplate, FooterTemplate)
    VALUES (
        'otp_login',
        'user',
        N'<div data-yo-c="true" data-yo-id="comp_seed_otp" data-yo-type="rawhtml" data-yo-name="Raw HTML" data-yo-config="{&quot;content&quot;:&quot;<table width=\&quot;100%\&quot; border=\&quot;0\&quot; cellspacing=\&quot;0\&quot; cellpadding=\&quot;0\&quot;><tr><td style=\&quot;padding-bottom:35px;\&quot;><table width=\&quot;100%\&quot; border=\&quot;0\&quot; cellspacing=\&quot;0\&quot; cellpadding=\&quot;0\&quot;><tr><td style=\&quot;font-size:18px; line-height:26px; color:#1b2430; font-family:Arial, Helvetica, sans-serif; text-align:left; padding-bottom:20px;\&quot;>Dear <strong>{{User}}</strong>,</td></tr><tr><td style=\&quot;font-size:36px; line-height:40px; color:#1b2430; font-family:Arial, Helvetica, sans-serif; text-align:center; padding-bottom:15px;\&quot;><strong>Your Login OTP Code</strong></td></tr><tr><td style=\&quot;font-size:16px; color:#6f7b8a; font-family:Arial, Helvetica, sans-serif; line-height:26px; text-align:left;\&quot;>Use the one-time password below to complete your login. This code is valid for <strong>{{OtpExpiryMinutes}} minutes</strong>. For your security, do not share it with anyone.</td></tr></table></td></tr></table><table width=\&quot;100%\&quot; border=\&quot;0\&quot; cellspacing=\&quot;0\&quot; cellpadding=\&quot;0\&quot;><tr><td align=\&quot;center\&quot; style=\&quot;padding-bottom:30px;\&quot;><table border=\&quot;0\&quot; cellspacing=\&quot;0\&quot; cellpadding=\&quot;0\&quot;><tr><td bgcolor=\&quot;#008cff\&quot; style=\&quot;font-size:28px; line-height:32px; letter-spacing:6px; mso-padding-alt:18px 40px; font-family:Arial, Helvetica, sans-serif; text-align:center; font-weight:bold; border-radius:10px; color:#ffffff; padding:18px 40px;\&quot;>{{OTP}}</td></tr></table></td></tr></table><table width=\&quot;100%\&quot; border=\&quot;0\&quot; cellspacing=\&quot;0\&quot; cellpadding=\&quot;0\&quot;><tr><td style=\&quot;text-align:center; padding-bottom:10px; font-size:12px; color:#6f7b8a; font-family:Arial, Helvetica, sans-serif;\&quot;>Requested at {{RequestedAt}} from {{RequestIp}}</td></tr></table>&quot;}"><table width="100%" border="0" cellspacing="0" cellpadding="0"><tr><td style="padding-bottom:35px;"><table width="100%" border="0" cellspacing="0" cellpadding="0"><tr><td style="font-size:18px; line-height:26px; color:#1b2430; font-family:Arial, Helvetica, sans-serif; text-align:left; padding-bottom:20px;">Dear <strong>{{User}}</strong>,</td></tr><tr><td style="font-size:36px; line-height:40px; color:#1b2430; font-family:Arial, Helvetica, sans-serif; text-align:center; padding-bottom:15px;"><strong>Your Login OTP Code</strong></td></tr><tr><td style="font-size:16px; color:#6f7b8a; font-family:Arial, Helvetica, sans-serif; line-height:26px; text-align:left;">Use the one-time password below to complete your login. This code is valid for <strong>{{OtpExpiryMinutes}} minutes</strong>. For your security, do not share it with anyone.</td></tr></table></td></tr></table><table width="100%" border="0" cellspacing="0" cellpadding="0"><tr><td align="center" style="padding-bottom:30px;"><table border="0" cellspacing="0" cellpadding="0"><tr><td bgcolor="#008cff" style="font-size:28px; line-height:32px; letter-spacing:6px; mso-padding-alt:18px 40px; font-family:Arial, Helvetica, sans-serif; text-align:center; font-weight:bold; border-radius:10px; color:#ffffff; padding:18px 40px;">{{OTP}}</td></tr></table></td></tr></table><table width="100%" border="0" cellspacing="0" cellpadding="0"><tr><td style="text-align:center; padding-bottom:10px; font-size:12px; color:#6f7b8a; font-family:Arial, Helvetica, sans-serif;">Requested at {{RequestedAt}} from {{RequestIp}}</td></tr></table></div>',
        'Your Login OTP Code',
        1, 0, GETUTCDATE(), 1, 0, '', '');
END
GO
